for (let i: number = 1; i <= 5; i++) {
  console.log(`Repetição ${i}`);
}

// Contagem regressiva!
for (let t: number = 10; t >= 1; t--) {
  console.log(t);
}
console.log("LANÇAR!");

// Somando números de 1 a 100
let soma: number = 0;

for (let i: number = 1; i <= 100; i++) {
  soma = soma + i;
}

console.log(`A soma de 1 até 100 é: ${soma}`);

let hpMonstro: number = 50;
let ataque: number = 15;
let turno: number = 1;

while (hpMonstro > 0) {
  hpMonstro = hpMonstro - ataque;
  console.log(`Turno ${turno}: Monstro com ${Math.max(0, hpMonstro)} HP`);
  turno++;
}

console.log("Monstro derrotado!");

// break: acha o primeiro múltiplo de 7 e para
for (let i: number = 1; i <= 100; i++) {
  if (i % 7 === 0) {
    console.log(`Primeiro múltiplo de 7: ${i}`);
    break;
  }
}

// continue: imprime só os números ímpares
for (let i: number = 1; i <= 10; i++) {
  if (i % 2 === 0) {
    continue;
  }
  console.log(i);
}

for (let linha: number = 1; linha <= 3; linha++) {
  let texto: string = "";
  for (let coluna: number = 1; coluna <= 3; coluna++) {
    texto += `(${linha},${coluna}) `;
  }
  console.log(texto);
}

